# Regex pattern for valid PostgreSQL extension names
VALID_EXTENSION_NAME_PATTERN = re.compile(r'^[a-zA-Z][a-zA-Z0-9_-]*$')


def validate_extension_name(extension_name: str) -> tuple[bool, str]:
    """Validate the extension name against whitelist and format rules."""
    if not extension_name:
        return False, "Extension name cannot be empty."

    extension_name = extension_name.strip().lower()

    if not VALID_EXTENSION_NAME_PATTERN.match(extension_name):
        return False, (
            f"Invalid extension name format: '{extension_name}'. "
            "Extension names must start with a letter and contain only "
            "letters, digits, underscores, or hyphens."
        )

    if extension_name not in ALLOWED_EXTENSIONS:
        return False, (
            f"Extension '{extension_name}' is not in the allowed extensions whitelist. "
            f"Allowed extensions: {', '.join(sorted(ALLOWED_EXTENSIONS))}"
        )

    return True, extension_name


def get_db_connection(host: str, port: int, dbname: str, user: str, password: str):
    """Create and return a database connection."""
    conn = psycopg2.connect(
        host=host,
        port=port,
        dbname=dbname,
        user=user,
        password=password,
        connect_timeout=10,
    )
    conn.autocommit = True
    return conn


def list_installed_extensions(conn) -> list[dict]:
    """List all currently installed extensions."""
    with conn.cursor() as cur:
        cur.execute(
            "SELECT extname, extversion, extrelocatable FROM pg_extension ORDER BY extname;"
        )
        rows = cur.fetchall()
        return [
            {"name": row[0], "version": row[1], "relocatable": row[2]}
            for row in rows
        ]


def install_extension(conn, extension_name: str, if_not_exists: bool = True) -> tuple[bool, str]:
    """
    Safely install a PostgreSQL extension using parameterized identifiers.

    Uses psycopg2.sql module to safely construct the query with proper
    identifier quoting, preventing SQL injection.
    """
    is_valid, result = validate_extension_name(extension_name)
    if not is_valid:
        return False, result

    sanitized_name = result

    try:
        with conn.cursor() as cur:
            if if_not_exists:
                query = psycopg2.sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )
            else:
                query = psycopg2.sql.SQL("CREATE EXTENSION {}").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )

            cur.execute(query)
            return True, f"Extension '{sanitized_name}' installed successfully."

    except psycopg2.errors.DuplicateObject:
        return False, f"Extension '{sanitized_name}' is already installed."
    except psycopg2.errors.UndefinedFile:
        return False, (
            f"Extension '{sanitized_name}' is not available on this server. "
            "Please ensure the extension package is installed on the system."
        )
    except psycopg2.errors.InsufficientPrivilege:
        return False, (
            f"Insufficient privileges to install extension '{sanitized_name}'. "
            "Superuser privileges may be required."
        )
    except psycopg2.Error as e:
        return False, f"Database error while installing '{sanitized_name}': {e}"


def uninstall_extension(conn, extension_name: str, cascade: bool = False) -> tuple[bool, str]:
    """Safely uninstall a PostgreSQL extension."""
    is_valid, result = validate_extension_name(extension_name)
    if not is_valid:
        return False, result

    sanitized_name = result

    try:
        with conn.cursor() as cur:
            if cascade:
                query = psycopg2.sql.SQL("DROP EXTENSION IF EXISTS {} CASCADE").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )
            else:
                query = psycopg2.sql.SQL("DROP EXTENSION IF EXISTS {}").format(
                    psycopg2.sql.Identifier(sanitized_name)
                )

            cur.execute(query)
            return True, f"Extension '{sanitized_name}' removed successfully."

    except psycopg2.errors.DependentObjectsStillExist:
        return False, (
            f"Extension '{sanitized_name}' has dependent objects. "
            "Use CASCADE option to force removal."
        )
    except psycopg2.errors.InsufficientPrivilege:
        return False, (
            f"Insufficient privileges to remove extension '{sanitized_name}'."
        )
    except psycopg2.Error as e:
        return False, f"Database error while removing '{sanitized_name}': {e}"


def check_extension_available(conn, extension_name: str) -> tuple[bool, str]:
    """Check if an extension is available for installation."""
    is_valid, result = validate_extension_name(extension_name)
    if not is_valid:
        return False, result

    sanitized_name = result

    try:
        with conn.cursor() as cur:
            cur.execute(
                "SELECT name, default_version, comment FROM pg_available_extensions WHERE name = %s;",
                (sanitized_name,)
            )
            row = cur.fetchone()
            if row:
                return True, (
                    f"Extension '{row[0]}' is available.\n"
                    f"  Version: {row[1]}\n"
                    f"  Description: {row[2]}"
                )
            else:
                return False, f"Extension '{sanitized_name}' is not available on this server."

    except psycopg2.Error as e:
        return False, f"Database error: {e}"


